SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , A.NLVL_BAS_SEQ , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM , A.NFCLT_MST_SEQ -- 장비 MST SEQ , A.SHOST_NM -- 호스트명 , A.SFCLT_TYPE -- 장비 타입 , A.SFCLT_MODEL_NM -- 장비명 , A.PTELNET_IP -- TELNET IP , A.NPORT_FCLT -- 장비PORT , A.PIP_PEER_FCLT -- PEER 장비 IP , A.PIP_UPPER_FCLT -- 상위 장비 IP , A.SUSE_YN -- 사용 여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , A.RNUM FROM ( SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , A.NLVL_BAS_SEQ , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM , A.NFCLT_MST_SEQ -- 장비 MST SEQ , A.SHOST_NM -- 호스트명 , A.SFCLT_TYPE -- 장비 타입 , A.SFCLT_MODEL_NM -- 장비명 , A.PTELNET_IP -- TELNET IP , A.NPORT_FCLT -- 장비PORT , A.PIP_PEER_FCLT -- PEER 장비 IP , A.PIP_UPPER_FCLT -- 상위 장비 IP , A.SUSE_YN -- 사용 여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , ROWNUM RNUM FROM ( SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , A.NLVL_BAS_SEQ , B.SSVC_LINE_TYPE_NM SSVC_LINE_TYPE_NM , C.SLVL_NM SSVC_GROUP_NM , D.SLVL_NM SSVC_OBJ_NM , E.NFCLT_MST_SEQ -- 장비 MST SEQ , E.SHOST_NM -- 호스트명 , E.SFCLT_TYPE -- 장비 타입 , E.SFCLT_MODEL_NM -- 장비명 , E.PTELNET_IP -- TELNET IP , E.NPORT_FCLT -- 장비PORT , E.PIP_PEER_FCLT -- PEER 장비 IP , E.PIP_UPPER_FCLT -- 상위 장비 IP , E.SUSE_YN -- 사용 여부 , E.DCREATE_DT , E.SCREATE_ID , E.DMODIFY_DT , E.SMODIFY_ID FROM MST.TB_LVL_BAS A , MST.TB_SVC_LINE_TYPE_CD B , MST.TB_LVL_CD C , MST.TB_LVL_CD D , MST.TB_INTGRM_FCLT_MST E -- 조직별 장비 MST WHERE 1=1 AND A.SSVC_LINE_TYPE_CD IN ('CL0001', 'CL0002', 'CL0003') AND A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.SSVC_GROUP_CD = C.SLVL_CD(+) AND A.SSVC_OBJ_CD = D.SLVL_CD(+) AND A.NLVL_BAS_SEQ = E.NLVL_BAS_SEQ(+)
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.SSVC_GROUP_CD = #{ssvcGroupCd, jdbcType=CHAR}
AND A.SSVC_OBJ_CD = #{ssvcObjCd, jdbcType=CHAR}
AND E.SFCLT_TYPE ILIKE '%' || #{sfcltType, jdbcType=CHAR} || '%'
AND E.SUSE_YN = #{suseYn, jdbcType=CHAR}
ORDER BY A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , E.NFCLT_MST_SEQ ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount FROM MST.TB_LVL_BAS A , MST.TB_SVC_LINE_TYPE_CD B , MST.TB_LVL_CD C , MST.TB_LVL_CD D , MST.TB_INTGRM_FCLT_MST E -- 조직별 장비 MST WHERE 1=1 AND A.SSVC_LINE_TYPE_CD IN ('CL0001', 'CL0002', 'CL0003') AND A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.SSVC_GROUP_CD = C.SLVL_CD(+) AND A.SSVC_OBJ_CD = D.SLVL_CD(+) AND A.NLVL_BAS_SEQ = E.NLVL_BAS_SEQ(+)
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.SSVC_GROUP_CD = #{ssvcGroupCd, jdbcType=CHAR}
AND A.SSVC_OBJ_CD = #{ssvcObjCd, jdbcType=CHAR}
AND E.SFCLT_TYPE ILIKE '%' || #{sfcltType, jdbcType=CHAR} || '%'
AND E.SUSE_YN = #{suseYn, jdbcType=CHAR}

mapper.insert:
INSERT
INTO MST.TB_INTGRM_FCLT_MST (
	NLVL_BAS_SEQ				-- 계위 BAS SEQ
	,   SHOST_NM					-- 호스트명
	,   SFCLT_TYPE				-- 장비 타입
	,   SFCLT_MODEL_NM 		-- 장비명
	,   PTELNET_IP 				-- TELNET IP
	,   NPORT_FCLT 				-- 장비PORT
	,   PIP_PEER_FCLT			-- PEER 장비 IP
	,   PIP_UPPER_FCLT			-- 상위 장비 IP
	,   SUSE_YN 					-- 사용 여부
	,	SCREATE_ID
	,	SMODIFY_ID

) VALUES (
	#{nlvlBasSeq, jdbcType=BIGINT}
	,	#{shostNm, jdbcType=VARCHAR}
	,	#{sfcltType, jdbcType=VARCHAR}
	,	#{sfcltModelNm, jdbcType=VARCHAR}
	,	#{ptelnetIp, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
	,	#{nportFclt, jdbcType=NUMERIC}
	,	#{pipPeerFclt, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
	,	#{pipUpperFclt, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
	,	#{suseYn, jdbcType=CHAR}
	,	#{screateId, jdbcType=VARCHAR}
	,	#{smodifyId, jdbcType=VARCHAR}
)

mapper.update:
UPDATE 
	MST.TB_INTGRM_FCLT_MST A  
SET

		A.NLVL_BAS_SEQ = #{nlvlBasSeq, jdbcType=BIGINT}


		, A.SHOST_NM = #{shostNm, jdbcType=CHAR}


		, A.SFCLT_TYPE = #{sfcltType, jdbcType=VARCHAR}


		, A.SFCLT_MODEL_NM = #{sfcltModelNm, jdbcType=VARCHAR}


		, A.PTELNET_IP = #{ptelnetIp, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}


		, A.NPORT_FCLT = #{nportFclt, jdbcType=NUMERIC}


		, A.PIP_PEER_FCLT = #{pipPeerFclt, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}


		, A.PIP_UPPER_FCLT = #{pipUpperFclt, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}


		, A.SUSE_YN = #{suseYn, jdbcType=CHAR}


		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

		, A.DMODIFY_DT = SYSDATE
WHERE 1=1
	     AND A.NFCLT_MST_SEQ = #{nfcltMstSeq, jdbcType=BIGINT}
